WITH BASE_RAW AS (
    SELECT
        CC.AL_CODICE AS CD_CONTROPARTE,
        -- Il primo record storico di ogni controparte (il piu' vecchio, dato che BASE_RAW
        -- rilegge sempre l'intero storico ad ogni run) usa AL_DATA_INSERIMENTO a
        -- mezzanotte come TS_INIZIO_VALIDITA invece di AL_DATA_MODIFICA/AL_ORA_MODIFICA.
        -- Calcolato qui (non dentro ts_fine_validita) perche' Snowflake non ammette
        -- window function annidate: ROW_NUMBER() non puo' comparire dentro l'argomento/
        -- ORDER BY del LEAD() di ts_fine_validita.
        CASE
            WHEN ROW_NUMBER() OVER (
                     PARTITION BY CC.AL_CODICE
                     ORDER BY CC.AL_DATA_MODIFICA, CC.AL_ORA_MODIFICA, CC.ROWID
                 ) = 1
                THEN COALESCE({{ custom_to_timestamp_ntz('CC.AL_DATA_INSERIMENTO') }}, {{ custom_to_timestamp_ntz('CC.AL_DATA_MODIFICA', 'CC.AL_ORA_MODIFICA') }})
            ELSE {{ custom_to_timestamp_ntz('CC.AL_DATA_MODIFICA', 'CC.AL_ORA_MODIFICA') }}
        END AS TS_INIZIO_VALIDITA,
        CC.AL_TIPO_ANAGRAFICA AS TP_CONTROPARTE,
        CC.AL_FORMA_GIURIDICA AS CD_FORMA_GIURIDICA,
        CC.AL_CODICE_FISCALE AS CD_FISCALE,
        CC.AL_CODICE_FISC_CALC AS FL_CF_CALCOLATO,
        CC.AL_CODICE_FISC_FORZ AS FL_CF_FORZATO,
        CC.AL_UTENTE_FORZATURA AS CD_UTENTE_FORZATURA_CF,
        CC.AL_PARTITA_IVA AS CD_PARTITA_IVA,
        CC.AL_NOME AS DS_NOME,
        CC.AL_SECONDO_NOME AS DS_SECONDO_NOME,
        CC.AL_COGNOME AS DS_COGNOME,
        CC.AL_COGNOME_MADRE AS DS_COGNOME_MADRE,
        CC.AL_RIFERIMENTO AS CD_RIFERIMENTO_ALTRA_ANAGRAFICA,
        CC.AL_MATRICOLA AS CD_MATRICOLA,
        CC.AL_RAG_SOCIALE_1 AS DS_RAGIONE_SOCIALE,
        CC.AL_RAG_SOCIALE_2 AS DS_RAGIONE_SOCIALE_2,
        CC.AL_CITTADINANZA AS CD_CITTADINANZA,
        CC.AL_NASCITA_LUOGO AS DS_CITTA_NASCITA,
        CC.AL_NASCITA_NAZIONE AS CD_NAZIONE_NASCITA,
        CC.AL_NASCITA_PROV AS CD_PROVINCIA_NASCITA,
