        {{ custom_to_date('CC.AL_NASCITA_DATA') }} AS DT_NASCITA,
        CC.AL_SESSO AS CD_SESSO,
        {{ custom_to_date('CC.AL_DATA_CESSAZIONE') }} AS DT_DECESSO,
        CC.AL_ABI AS CD_ABI,
        CC.AL_COD_IDEN AS CD_IDENTIFICATIVO,
