        CC.AL_CODICE_NDG2 AS CD_NDG2,
        CC.AL_CODICE_NDG3 AS CD_NDG3,
        CC.AL_CODICE_NDG_CRF AS CD_NDG_CRF,
        CC.AL_INPS_MATRICOLA AS CD_INPS_MATRICOLA,
        CC.AL_INAIL_PAT AS CD_INAIL_PAT,
        CC.AL_IPA AS CD_IPA,
        CC.AL_FILIALE AS CD_FILIALE,
