        CC.AL_TELEFONO_SEDE AS NM_TELEFONO_SEDE,
        CC.AL_FAX AS DS_FAX,
        CC.AL_EMAIL AS DS_EMAIL,
        CC.AL_EMAIL_PEC AS DS_EMAIL_PEC,
        CC.AL_POSIZIONE AS CD_OCCUPAZIONE,
        CC.AL_OCC_OCCUPAZIONE AS CD_OCCUPAZIONE_2,
        {{ custom_to_date('CC.AL_DATA_POSIZIONE') }} AS DT_OCCUPAZIONE,
        CC.AL_OCC_TIPO_ATTIVITA AS CD_TIPO_ATTIVITA_OCCUPAZIONE,
        CC.AL_OCC_SETTORE AS CD_SETTORE_OCCUPAZIONE,
        {{ custom_to_date('CC.AL_DL_OCCUPAZIONE_DAL') }}
            AS DT_INIZIO_OCCUPAZIONE_CLI,
        {{ custom_to_date('CC.AL_DL_OCCUPAZIONE_AL') }}
            AS DT_FINE_OCCUPAZIONE_CLI,
        CC.AL_ST_FLAG_ALBO_ARTIG AS FL_ISCRITTO_ALBO_ARTIGIANI,
        CC.AL_ST_NUM_DIPENDENTI AS NM_DIPENDENTI,
        CC.AL_CAPITALE_SOCIALE AS NM_CAPITALE_SOCIALE,
        CC.AL_PARTEC_ENTE_PUB AS FL_PARTECIPATA_ENTE_PUBBLICO,
        CC.AL_DL_DENOMINAZIONE AS DS_DATORE_LAVORO,
        CC.AL_DL_CODICE_FISCALE AS CD_FISCALE_DATORE_LAVORO,
        CC.AL_DL_PARTITA_IVA AS CD_PARTITA_IVA_DATORE_LAVORO,
