        {{ custom_to_date('CC.AL_DT_PRIVACY_ISTRUTT') }} AS DT_CONSENSO_IPR,
        {{ custom_to_date('CC.AL_DT_RILEV_QUALITA') }} AS DT_CONSENSO_SRQ,
        {{ custom_to_date('CC.AL_DT_PRIVACY_OFFERTE') }} AS DT_CONSENSO_OCI,
        {{ custom_to_date('CC.AL_DT_OFF_COMM_INT_AUT') }} AS DT_CONSENSO_OIA,
        {{ custom_to_date('CC.AL_DT_OFF_COMM_ESTERNE') }} AS DT_CONSENSO_OCE,
        {{ custom_to_date('CC.AL_DT_OFF_COMM_EST_AUT') }} AS DT_CONSENSO_OEA,
        {{ custom_to_date('CC.AL_DT_SERVIZI_ALTRI') }} AS DT_CONSENSO_OSA,
