        CC.AL_LEG_LOCALITA AS DS_COMUNE_LEGALE_RAPPRESENTANTE,
        CC.AL_LEG_PROVINCIA AS CD_PROVINCIA_LEGALE_RAPPRESENTANTE,
        {{ custom_to_date('CC.AL_LEG_DATA_NASCITA') }}
            AS DT_NASCITA_LEGALE_RAPPRESENTANTE,
        CC.AL_LEG_LUOGO_NASCITA AS DS_LOUGO_NASCITA_LEGALE_RAPPRESENTANTE,
