        {{ custom_to_date('CC.AL_DATA_ANNULLO') }} AS DT_ANNULLO,
        {{ custom_to_date('CC.AL_DATA_INSERIMENTO') }} AS DT_INSERIMENTO,
        CC.AL_UTENTE_INSERIMENTO AS CD_UTENTE_INSERIMENTO,
        {{ custom_to_date('CC.AL_DATA_VARIAZIONE') }} AS DT_VARIAZIONE,
        CC.AL_UTENTE_VARIAZIONE AS CD_UTENTE_VARIAZIONE,
        {{ custom_to_date('CC.AL_DATA_TRASMISSIONE') }} AS DT_TRASMISSIONE,
        CC.AL_RICER_1 AS DS_STRINGA_RICERCA,
        CC.AL_USER_1 AS CD_USER_1,
        CC.AL_USER_2 AS CD_USER_2,
        CC.AL_USER_3 AS CD_USER_3,
        CC.AL_NORMALIZZATO_RAG AS FL_NORM_DENOMINAZIONE,
        CC.AL_NORMALIZZATO_LOC AS FL_NORM_LOCALITA,
        CC.AL_NORMALIZZATO_IND AS FL_NORM_INDIRIZZO,
        CC.AL_NOTA_01 AS DS_NOTA_01,
        CC.AL_NOTA_02 AS DS_NOTA_02,
        CC.AL_FIL_CASELLA_POSTALE AS CD_FILIALE_CASELLA_POSTALE,
        CC.AL_NUM_CASELLA_POSTALE AS NM_CASELLA_POSTALE,
        CC.LASTMODIFIEDDATA,
        ROW_NUMBER() OVER (
            PARTITION BY CC.AL_CODICE, CC.AL_DATA_MODIFICA, CC.AL_ORA_MODIFICA
            ORDER BY CC.ROWID
        )::NUMBER(38, 0) AS PR_PK
    FROM {{ ref('ccanalog') }} AS CC
    WHERE CC.FL_DELETED = 'N'
),

