        DS_NOME_LEGALE_RAPPRESENTANTE,
        DS_INDIRIZZO_LEGALE_RAPPRESENTANTE,
        DS_PRESSO_LEGALE_RAPPRESENTANTE,
        CD_CAP_LEGALE_RAPPRESENTANTE,
        DS_FRAZIONE_LEGALE_RAPPRESENTANTE,
        DS_COMUNE_LEGALE_RAPPRESENTANTE,
        CD_PROVINCIA_LEGALE_RAPPRESENTANTE,
        DT_NASCITA_LEGALE_RAPPRESENTANTE,
        DS_LOUGO_NASCITA_LEGALE_RAPPRESENTANTE,
        CD_PROVINCIA_NASCITA_LEGALE_RAPPRESENTANTE,
        CD_NAZIONE_NASCITA_LEGALE_RAPPRESENTANTE,
        CD_CITTADINANZA_LEGALE_RAPPRESENTANTE,
        CD_CAUSALE_ANNULLO,
        DT_ANNULLO,
        DT_INSERIMENTO,
        CD_UTENTE_INSERIMENTO,
        DT_VARIAZIONE,
        CD_UTENTE_VARIAZIONE,
        DT_TRASMISSIONE,
        DS_STRINGA_RICERCA,
        CD_USER_1,
        CD_USER_2,
        CD_USER_3,
        FL_NORM_DENOMINAZIONE,
        FL_NORM_LOCALITA,
        FL_NORM_INDIRIZZO,
        DS_NOTA_01,
        DS_NOTA_02,
        CD_FILIALE_CASELLA_POSTALE,
        NM_CASELLA_POSTALE,
        LASTMODIFIEDDATA,
        PR_PK,
        {{ ts_fine_validita('CD_CONTROPARTE', 'TS_INIZIO_VALIDITA') }} AS TS_FV_NEXT
    FROM DEDUP
)

SELECT
    H.CD_CONTROPARTE,
    H.TS_INIZIO_VALIDITA,
    MAX(H.TS_FV_NEXT) OVER (
        PARTITION BY H.CD_CONTROPARTE, H.TS_INIZIO_VALIDITA
    ) AS TS_FINE_VALIDITA,
    H.PR_PK,
    {% if is_incremental() -%}
    COALESCE(
        EX.PR_CONTROPARTE,
        COALESCE(MX.MAX_PR_CONTROPARTE, 0) + ROW_NUMBER() OVER (
            PARTITION BY
                H.CD_CONTROPARTE, IFF(EX.PR_CONTROPARTE IS NULL, 1, 0)
            ORDER BY H.TS_INIZIO_VALIDITA, H.PR_PK
        )
    )::NUMBER(38, 0) AS PR_CONTROPARTE,
    {%- else -%}
    ROW_NUMBER() OVER (
        PARTITION BY H.CD_CONTROPARTE
        ORDER BY H.TS_INIZIO_VALIDITA, H.PR_PK
    )::NUMBER(38, 0) AS PR_CONTROPARTE,
    {%- endif %}
    H.TP_CONTROPARTE,
    H.CD_FORMA_GIURIDICA,
    H.CD_FISCALE,
    H.FL_CF_CALCOLATO,
    H.FL_CF_FORZATO,
    H.CD_UTENTE_FORZATURA_CF,
    H.CD_PARTITA_IVA,
    H.DS_NOME,
    H.DS_SECONDO_NOME,
    H.DS_COGNOME,
    H.DS_COGNOME_MADRE,
    H.CD_RIFERIMENTO_ALTRA_ANAGRAFICA,
    H.CD_MATRICOLA,
    H.DS_RAGIONE_SOCIALE,
    H.DS_RAGIONE_SOCIALE_2,
    H.CD_CITTADINANZA,
    CI1.CRECI_DESCRIZIONE AS DS_CITTADINANZA,
    H.DS_CITTA_NASCITA,
    H.CD_NAZIONE_NASCITA,
    NA1.ANATNA_DESCRIZIONE AS DS_NAZIONE_NASCITA,
    H.CD_PROVINCIA_NASCITA,
    PR1.ANATPR_DESCRIZIONE AS DS_PROVINCIA_NASCITA,
    H.DS_COMUNE_NASCITA,
    H.CD_CAB_COMUNE_NASCITA,
    H.DT_NASCITA,
    H.CD_SESSO,
    H.DT_DECESSO,
    H.CD_ABI,
    H.CD_IDENTIFICATIVO,
    H.CD_NDG,
    H.CD_NDG2,
    H.CD_NDG3,
    H.CD_NDG_CRF,
    H.CD_INPS_MATRICOLA,
    H.CD_INAIL_PAT,
    H.CD_IPA,
    H.CD_FILIALE,
    H.CD_FILIALE_STORICA,
    H.CD_ESENZIONE_IVA,
    H.CD_SETTORE_ATTIVITA,
    AT1.ANATAT_DESCRIZIONE AS DS_ATECO,
    H.CD_ATECO,
    H.CD_RAE,
    RA1.ANATRA_DESCRIZIONE AS DS_RAE,
    H.CD_SAE,
    SA1.ANATSA_DESCRIZIONE AS DS_SAE,
    H.CD_TAE,
    H.CD_CCIAA,
    H.TP_CCIAA,
    H.CD_PROVINCIA_CCIAA,
    PR2.ANATPR_DESCRIZIONE AS DS_PROVINCIA_CCIAA,
    H.DT_REGISTRAZIONE_CCIAA,
    H.FL_CONTROLLO_CCIAA,
    H.FL_FALLIBILE,
    H.DT_FALLIMENTO,
    H.TP_PROC_CONCORSUALI,
    H.TP_PROC_LEGALI,
    H.CD_DOCUMENTO,
    H.TP_DOCUMENTO,
    H.TP_EMITTENTE,
    H.DT_RILASCIO_DOC,
    H.DT_FINE_VALIDITA_DOC,
    H.DS_COMUNE_RILASCIO_DOC,
    H.CD_PROVINCIA_RILASCIO_DOC,
    PR3.ANATPR_DESCRIZIONE AS DS_PROVINCIA_RILASCIO_DOC,
    H.CD_NAZIONE_RILASCIO_DOC,
    NA2.ANATNA_DESCRIZIONE AS DS_NAZIONE_RILASCIO_DOC,
    H.CD_DOCUMENTO_2,
    H.NM_TESSERA_SANITARIA,
    H.DT_SCADENZA_TESSERA_SANITARIA,
    H.DS_NOTE_DOCUMENTO,
    H.FL_UNIVOCITA_DOCUMENTO,
    H.FL_SOSPETTO_FORZATO_DOCUMENTO,
    H.DS_PRESSO,
    H.DS_FRAZIONE,
    H.DS_INDIRIZZO_1,
    H.DT_INDIRIZZO_RESIDENZA_DAL,
    H.DS_INDIRIZZO_2,
    H.FL_INDIRIZZO_NORMALIZZATO,
    H.FL_INDIRIZZO_FORZATO,
    H.CD_CAP,
    PR4.ANATPR_REGIONE AS CD_REGIONE_RESIDENZA,
    RE1.ANATRE_DESCRIZIONE AS DS_REGIONE_RESIDENZA,
    H.CD_NAZIONE_RESIDENZA,
    NA3.ANATNA_DESCRIZIONE AS DS_NAZIONE_RESIDENZA,
    H.DS_COMUNE_RESIDENZA,
    H.CD_PROVINCIA_RESIDENZA,
    PR4.ANATPR_DESCRIZIONE AS DS_PROVINCIA_RESIDENZA,
    H.CD_CAB_RESIDENZA,
    H.CD_TIPO_SEDE,
    H.DS_SEDE_INDIRIZZO_1,
    H.DS_SEDE_INDIRIZZO_2,
    H.FL_SEDE_INDIRIZZO_NORMALIZZATO,
    H.FL_SEDE_INDIRIZZO_FORZATO,
    H.DS_SEDE_PRESSO,
    H.DS_SEDE_FRAZIONE,
    RE2.ANATRE_DESCRIZIONE AS DS_SEDE_REGIONE,
    H.CD_SEDE_PROVINCIA,
    PR5.ANATPR_DESCRIZIONE AS DS_SEDE_PROVINCIA,
    H.CD_SEDE_CAP,
    H.DS_SEDE_COMUNE,
    H.CD_SEDE_CAB_COMUNE,
    H.CD_SEDE_NAZIONE,
    NA4.ANATNA_DESCRIZIONE AS DS_SEDE_NAZIONE,
    H.TP_PERMESSO_SOGGIORNO,
    H.DT_INIZIO_PERMESSO_SOGGIORNO,
    H.DT_SCADENZA_PERMESSO_SOGGIORNO,
    H.FL_SCADENZA_FORZATA_PERMESSO,
    H.FL_VALIDITA_FORZATA_PERMESSO,
    H.NM_CELLULARE,
    H.NM_TELEFONO,
    H.NM_TELEFONO_UFFICIO,
    H.NM_TELEFONO_SEDE,
    H.DS_FAX,
    H.DS_EMAIL,
    H.DS_EMAIL_PEC,
    H.CD_OCCUPAZIONE,
    H.CD_OCCUPAZIONE_2,
    H.DT_OCCUPAZIONE,
    PO1.ANATPO_DESCRIZIONE AS DS_OCCUPAZIONE,
    H.CD_TIPO_ATTIVITA_OCCUPAZIONE,
    H.CD_SETTORE_OCCUPAZIONE,
    H.DT_INIZIO_OCCUPAZIONE_CLI,
    H.DT_FINE_OCCUPAZIONE_CLI,
    H.FL_ISCRITTO_ALBO_ARTIGIANI,
    H.NM_DIPENDENTI,
    H.NM_CAPITALE_SOCIALE,
    H.FL_PARTECIPATA_ENTE_PUBBLICO,
    H.DS_DATORE_LAVORO,
    H.CD_FISCALE_DATORE_LAVORO,
    H.CD_PARTITA_IVA_DATORE_LAVORO,
    H.CD_FORMA_GIURIDICA_DATORE_LAVORO,
    H.CD_IDEN_DATORE_LAVORO,
    H.DS_INDIRIZZO_DATORE_LAVORO,
    H.DS_PRESSO_DATORE_LAVORO,
    H.DS_COMUNE_DATORE_LAVORO,
    H.CD_CAP_INDIRIZZO_DATORE_LAVORO,
    H.DS_FRAZIONE_DATORE_LAVORO,
    H.CD_PROVINCIA_DATORE_LAVORO,
    PR6.ANATPR_DESCRIZIONE AS DS_PROVINCIA_DATORE_LAVORO,
    H.NM_TELEFONO_DATORE_LAVORO,
    H.FL_INDIRIZZO_NORMALIZZATO_DATORE_LAVORO,
    H.FL_INDIRIZZO_FORZATO_DATORE_LAVORO,
    H.DS_FAX_DATORE_LAVORO,
    H.FL_DIPENDENTE,
    H.FL_CLIENTE,
    H.FL_AGENTE,
    H.FL_TIPO_ALTRO,
    H.FL_GARANTE,
    H.FL_FORNITORE,
    H.FL_COOBLIGATO,
    H.FL_CONVENZIONATO,
    H.FL_DITTA,
    H.FL_FIRMATARIO,
    H.FL_DELEGATO,
    H.FL_FONDO_PENSIONE,
    H.FL_FINANZIARIA,
    H.FL_DATORE_LAVORO,
    H.TP_INTERMEDIARIO_ABILITATO,
    H.FL_ANA_DI_GRUPPO,
    H.FL_CLIENTE_BANCA,
    H.TP_CONSENSO_SRQ,
    H.TP_CONSENSO_OCI,
    H.TP_CONSENSO_OIA,
    H.TP_CONSENSO_OCE,
    H.TP_CONSENSO_OEA,
    H.TP_CONSENSO_OSA,
    H.TP_CONSENSO_DSU,
    H.TP_CONSENSO_SIC,
    H.TP_CONSENSO_IPR,
    H.DT_CONSENSO_IPR,
    H.DT_CONSENSO_SRQ,
    H.DT_CONSENSO_OCI,
    H.DT_CONSENSO_OIA,
    H.DT_CONSENSO_OCE,
    H.DT_CONSENSO_OEA,
    H.DT_CONSENSO_OSA,
    H.DT_CONSENSO_DSU,
    H.DT_CONSENSO_CIS,
    H.DS_NOTE_SIC,
    H.TP_CANCELLAZIONE_DATI_PRIVACY,
    H.EU_REDDITO_ANNUO,
    H.NM_MENSILITA_REDDITO,
    H.EU_ALTRI_REDDITI,
    H.TP_REDDITO,
    H.EU_REDDITO_FAMILIARE,
    H.EU_REDDITO_FAMILIARE_CONIUGE,
    H.CD_CENTRALE_RISCHI,
    H.CD_SIA,
    H.CD_LEGALE_RAPPRESENTANTE,
    H.DS_NOME_LEGALE_RAPPRESENTANTE,
    H.DS_INDIRIZZO_LEGALE_RAPPRESENTANTE,
    H.DS_PRESSO_LEGALE_RAPPRESENTANTE,
    H.CD_CAP_LEGALE_RAPPRESENTANTE,
    H.DS_FRAZIONE_LEGALE_RAPPRESENTANTE,
    H.DS_COMUNE_LEGALE_RAPPRESENTANTE,
    H.CD_PROVINCIA_LEGALE_RAPPRESENTANTE,
    PR7.ANATPR_DESCRIZIONE AS DS_PROVINCIA_LEGALE_RAPPRESENTANTE,
    H.DT_NASCITA_LEGALE_RAPPRESENTANTE,
    H.DS_LOUGO_NASCITA_LEGALE_RAPPRESENTANTE,
    H.CD_PROVINCIA_NASCITA_LEGALE_RAPPRESENTANTE,
    PR8.ANATPR_DESCRIZIONE AS DS_PROVINCIA_NASCITA_LEGALE_RAPPRESENTANTE,
    H.CD_NAZIONE_NASCITA_LEGALE_RAPPRESENTANTE,
    NA5.ANATNA_DESCRIZIONE AS DS_NAZIONE_NASCITA_LEGALE_RAPPRESENTANTE,
    H.CD_CITTADINANZA_LEGALE_RAPPRESENTANTE,
    CI2.CRECI_DESCRIZIONE AS DS_CITTADINANZA_LEGALE_RAPPRESENTANTE,
    H.CD_CAUSALE_ANNULLO,
    H.DT_ANNULLO,
    H.DT_INSERIMENTO,
    H.CD_UTENTE_INSERIMENTO,
    H.DT_VARIAZIONE,
    H.CD_UTENTE_VARIAZIONE,
    H.DT_TRASMISSIONE,
    H.DS_STRINGA_RICERCA,
    H.CD_USER_1,
    H.CD_USER_2,
    H.CD_USER_3,
    H.FL_NORM_DENOMINAZIONE,
    H.FL_NORM_LOCALITA,
    H.FL_NORM_INDIRIZZO,
    H.DS_NOTA_01,
    H.DS_NOTA_02,
    H.CD_FILIALE_CASELLA_POSTALE,
    H.NM_CASELLA_POSTALE,
    H.LASTMODIFIEDDATA
FROM DEDUP_FV AS H
LEFT JOIN {{ ref('cccretci') }} AS CI1
    ON
        H.CD_CITTADINANZA = CI1.CRECI_CITTADINANZA
        AND H.TS_INIZIO_VALIDITA >= CI1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < CI1.TS_FINE_VALIDITA
        AND CI1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatna') }} AS NA1
    ON
        H.CD_NAZIONE_NASCITA = NA1.ANATNA_NAZIONE
        AND H.TS_INIZIO_VALIDITA >= NA1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < NA1.TS_FINE_VALIDITA
        AND NA1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR1
    ON
        H.CD_PROVINCIA_NASCITA = PR1.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR1.TS_FINE_VALIDITA
        AND PR1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatat') }} AS AT1
    ON
        H.CD_ATECO = AT1.ANATAT_ATECO
        AND H.TS_INIZIO_VALIDITA >= AT1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < AT1.TS_FINE_VALIDITA
        AND AT1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatra') }} AS RA1
    ON
        H.CD_RAE = RA1.ANATRA_RAE
        AND H.TS_INIZIO_VALIDITA >= RA1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < RA1.TS_FINE_VALIDITA
        AND RA1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatsa') }} AS SA1
    ON
        H.CD_SAE = SA1.ANATSA_SAE
        AND H.TS_INIZIO_VALIDITA >= SA1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < SA1.TS_FINE_VALIDITA
        AND SA1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR2
    ON
        H.CD_PROVINCIA_CCIAA = PR2.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR2.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR2.TS_FINE_VALIDITA
        AND PR2.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR3
    ON
        H.CD_PROVINCIA_RILASCIO_DOC = PR3.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR3.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR3.TS_FINE_VALIDITA
        AND PR3.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatna') }} AS NA2
    ON
        H.CD_NAZIONE_RILASCIO_DOC = NA2.ANATNA_NAZIONE
        AND H.TS_INIZIO_VALIDITA >= NA2.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < NA2.TS_FINE_VALIDITA
        AND NA2.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR4
    ON
        H.CD_PROVINCIA_RESIDENZA = PR4.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR4.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR4.TS_FINE_VALIDITA
        AND PR4.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatre') }} AS RE1
    ON
        PR4.ANATPR_REGIONE = RE1.ANATRE_REGIONE
        AND H.TS_INIZIO_VALIDITA >= RE1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < RE1.TS_FINE_VALIDITA
        AND RE1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatna') }} AS NA3
    ON
        H.CD_NAZIONE_RESIDENZA = NA3.ANATNA_NAZIONE
        AND H.TS_INIZIO_VALIDITA >= NA3.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < NA3.TS_FINE_VALIDITA
        AND NA3.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR5
    ON
        H.CD_SEDE_PROVINCIA = PR5.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR5.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR5.TS_FINE_VALIDITA
        AND PR5.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatre') }} AS RE2
    ON
        PR5.ANATPR_REGIONE = RE2.ANATRE_REGIONE
        AND H.TS_INIZIO_VALIDITA >= RE2.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < RE2.TS_FINE_VALIDITA
        AND RE2.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatna') }} AS NA4
    ON
        H.CD_SEDE_NAZIONE = NA4.ANATNA_NAZIONE
        AND H.TS_INIZIO_VALIDITA >= NA4.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < NA4.TS_FINE_VALIDITA
        AND NA4.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpo') }} AS PO1
    ON
        H.CD_OCCUPAZIONE = PO1.ANATPO_POSIZ_CONTROP
        AND H.TS_INIZIO_VALIDITA >= PO1.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PO1.TS_FINE_VALIDITA
        AND PO1.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR6
    ON
        H.CD_PROVINCIA_DATORE_LAVORO = PR6.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR6.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR6.TS_FINE_VALIDITA
        AND PR6.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR7
    ON
        H.CD_PROVINCIA_LEGALE_RAPPRESENTANTE = PR7.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR7.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR7.TS_FINE_VALIDITA
        AND PR7.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatpr') }} AS PR8
    ON
        H.CD_PROVINCIA_NASCITA_LEGALE_RAPPRESENTANTE = PR8.ANATPR_PROVINCIA
        AND H.TS_INIZIO_VALIDITA >= PR8.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < PR8.TS_FINE_VALIDITA
        AND PR8.FL_DELETED = 'N'
LEFT JOIN {{ ref('ccanatna') }} AS NA5
    ON
        H.CD_NAZIONE_NASCITA_LEGALE_RAPPRESENTANTE = NA5.ANATNA_NAZIONE
        AND H.TS_INIZIO_VALIDITA >= NA5.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < NA5.TS_FINE_VALIDITA
        AND NA5.FL_DELETED = 'N'
LEFT JOIN {{ ref('cccretci') }} AS CI2
    ON
        H.CD_CITTADINANZA_LEGALE_RAPPRESENTANTE = CI2.CRECI_CITTADINANZA
        AND H.TS_INIZIO_VALIDITA >= CI2.TS_INIZIO_VALIDITA
        AND H.TS_INIZIO_VALIDITA < CI2.TS_FINE_VALIDITA
        AND CI2.FL_DELETED = 'N'
{%- if is_incremental() %}
LEFT JOIN {{ this }} AS EX
    ON
        H.CD_CONTROPARTE = EX.CD_CONTROPARTE
        AND H.TS_INIZIO_VALIDITA = EX.TS_INIZIO_VALIDITA
        AND H.PR_PK = EX.PR_PK
LEFT JOIN (
    SELECT
        CD_CONTROPARTE,
        MAX(PR_CONTROPARTE) AS MAX_PR_CONTROPARTE
    FROM {{ this }}
    GROUP BY CD_CONTROPARTE
) AS MX
    ON H.CD_CONTROPARTE = MX.CD_CONTROPARTE
{%- endif %}
